import { useEffect, useRef, useState } from 'react';
import { getLifetimeStats, avgMistakes, avgTimeMs, resetLifetimeStats, type LifetimeStats } from '../../state/lifetime-stats';
import { getStreak } from '../../state/streak-store';
import { CATALOG, isUnlocked, resetAchievements } from '../../state/achievements';
import { trapFocus } from '../a11y/trap-focus';
import { useGameActions } from '../../state/store';
import type { EtchSize } from '../../engine';
import '../achievements/achievements.css';
import '../onboarding/onboarding.css';
import './stats.css';

const SIZE_ORDER: EtchSize[] = ['sketch', 'beginner', 'intermediate', 'tall', 'expert'];

function fmt(ms: number): string {
  if (ms <= 0) return '—';
  const total = Math.floor(ms / 1000);
  const m = Math.floor(total / 60), s = total % 60;
  return `${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`;
}

interface Props { onClose: () => void; }

/**
 * Personal stats screen — lazy-loaded sheet.
 * Shows: lifetime puzzles solved, current/longest streak, perfect-solve count,
 * average mistakes, average time, plus a per-size best-time grid.
 */
export function StatsSheet({ onClose }: Props) {
  const sheetRef = useRef<HTMLDivElement>(null);
  const [stats, setStats] = useState<LifetimeStats>(() => getLifetimeStats());
  const [confirmReset, setConfirmReset] = useState(false);
  const streak = getStreak();
  const a = useGameActions();
  const isEmpty = stats.puzzlesSolved === 0;

  useEffect(() => {
    const n = sheetRef.current;
    if (!n) return;
    const release = trapFocus(n);
    function onKey(e: KeyboardEvent) { if (e.key === 'Escape') onClose(); }
    window.addEventListener('keydown', onKey);
    return () => { release(); window.removeEventListener('keydown', onKey); };
  }, [onClose]);

  function doReset() {
    resetLifetimeStats();
    resetAchievements();
    setStats(getLifetimeStats());
    setConfirmReset(false);
  }
  const unlockedCount = CATALOG.reduce((n, a) => n + (isUnlocked(a.id) ? 1 : 0), 0);

  const completionRate = stats.puzzlesStarted > 0
    ? Math.round((stats.puzzlesSolved / stats.puzzlesStarted) * 100)
    : 0;

  return (
    <div
      className="etch-stats-backdrop"
      role="dialog"
      aria-modal="true"
      aria-label="Personal stats"
      onClick={onClose}
    >
      <div
        className="etch-stats-sheet"
        ref={sheetRef}
        onClick={(e) => e.stopPropagation()}
      >
        <header>
          <h2>Your stats</h2>
          <button onClick={onClose} aria-label="Close" className="etch-stats-close">×</button>
        </header>

        {isEmpty && (
          <section className="etch-empty-state" data-testid="stats-empty">
            <svg viewBox="0 0 50 50" className="etch-empty-art" aria-hidden="true">
              <rect width="50" height="50" rx="6" className="etch-empty-art-bg" />
              <rect x="15" y="22" width="20" height="6" rx="1" className="etch-empty-art-cell" />
              <rect x="22" y="15" width="6" height="20" rx="1" className="etch-empty-art-cell" />
            </svg>
            <h3 className="etch-empty-title">No streak yet</h3>
            <p className="etch-empty-body">
              Win your first puzzle to start your streak and unlock achievements.
            </p>
            <button
              type="button"
              className="etch-empty-cta"
              onClick={() => { onClose(); void a.startIntro(); }}
              data-testid="stats-empty-cta"
            >
              Play your first puzzle
            </button>
          </section>
        )}

        <section className="etch-stats-top">
          <div className="etch-stats-tile">
            <span className="etch-stats-tile-num">{stats.puzzlesSolved}</span>
            <span className="etch-stats-tile-lbl">Solved</span>
          </div>
          <div className="etch-stats-tile">
            <span className="etch-stats-tile-num">{streak.current}</span>
            <span className="etch-stats-tile-lbl">Streak</span>
          </div>
          <div className="etch-stats-tile">
            <span className="etch-stats-tile-num">{streak.longest}</span>
            <span className="etch-stats-tile-lbl">Best streak</span>
          </div>
          <div className="etch-stats-tile">
            <span className="etch-stats-tile-num">{stats.perfectSolves}</span>
            <span className="etch-stats-tile-lbl">Perfect</span>
          </div>
        </section>

        <section className="etch-stats-row">
          <div>
            <h3>Average time</h3>
            <p className="etch-stats-big">{fmt(avgTimeMs(stats))}</p>
          </div>
          <div>
            <h3>Avg mistakes</h3>
            <p className="etch-stats-big">
              {stats.puzzlesSolved > 0 ? avgMistakes(stats).toFixed(1) : '—'}
            </p>
          </div>
          <div>
            <h3>Completion</h3>
            <p className="etch-stats-big">{completionRate}%</p>
          </div>
        </section>

        <section>
          <h3>Best time per size</h3>
          <table className="etch-stats-table">
            <thead>
              <tr><th>Size</th><th>Solved</th><th>Best</th></tr>
            </thead>
            <tbody>
              {SIZE_ORDER.map(size => {
                const row = stats.bySize[size];
                return (
                  <tr key={size}>
                    <td>{size}</td>
                    <td>{row?.solved ?? 0}</td>
                    <td>{row?.bestMs != null ? fmt(row.bestMs) : '—'}</td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </section>

        <section data-testid="achievements-tray">
          <h3>Achievements</h3>
          <p className="etch-ach-summary">{unlockedCount} of {CATALOG.length} unlocked</p>
          <div className="etch-ach-tray">
            {CATALOG.map((a) => {
              const ok = isUnlocked(a.id);
              return (
                <div
                  key={a.id}
                  className="etch-ach-tile"
                  data-locked={ok ? undefined : '1'}
                  data-id={a.id}
                  title={ok ? a.desc : `Locked — ${a.desc}`}
                >
                  <span className="etch-ach-tile-icon" aria-hidden="true">★</span>
                  <span className="etch-ach-tile-label">{a.label}</span>
                  <span className="etch-ach-tile-desc">{a.desc}</span>
                </div>
              );
            })}
          </div>
        </section>

        <section className="etch-stats-danger">
          {confirmReset ? (
            <div className="etch-stats-confirm">
              <span>Reset all stats?</span>
              <button onClick={doReset} className="etch-stats-confirm-yes">Yes, reset</button>
              <button onClick={() => setConfirmReset(false)} className="etch-stats-confirm-no">Cancel</button>
            </div>
          ) : (
            <button
              onClick={() => setConfirmReset(true)}
              className="etch-stats-reset"
              type="button"
            >
              Reset stats
            </button>
          )}
        </section>
      </div>
    </div>
  );
}

export default StatsSheet;
